CREATE TABLE IF NOT EXISTS public.bapperida_metrics (id VARCHAR(50) PRIMARY KEY, label VARCHAR(255), value VARCHAR(255), icon VARCHAR(50), priority INT);
INSERT INTO public.bapperida_metrics (id, label, value, icon, priority) VALUES ('ipd_2025', 'Indeks Pembangunan Daerah Kabupaten Sumba Barat', 'Menunggu Data', '📈', 1), ('iprid_2025', 'Indeks Pemanfaatan Riset dan Inovasi Daerah', 'Menunggu Data', '🔬', 2), ('sakip_2025', 'NILAI SAKIP Bapperida Tahun 2025', 'Menunggu Data', '🏆', 3) ON CONFLICT DO NOTHING;
CREATE TABLE IF NOT EXISTS public.bapperida_inovasi (id SERIAL PRIMARY KEY, opd_nama VARCHAR(255), judul_inovasi VARCHAR(255), nama_inovator VARCHAR(255), jenis_inovasi VARCHAR(100), tahapan_inovasi VARCHAR(100), rancang_bangun TEXT, waktu_uji_coba DATE, waktu_penerapan DATE, link_video VARCHAR(255), dokumen_dukung JSONB, skor_iga INT DEFAULT 0, kategori_skor VARCHAR(50), status_approval VARCHAR(50) DEFAULT 'Pending', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
ALTER TABLE public.bapperida_inovasi ADD COLUMN IF NOT EXISTS nama_inovator VARCHAR(255);
ALTER TABLE public.bapperida_inovasi ADD COLUMN IF NOT EXISTS regulasi_inovasi VARCHAR(100);
ALTER TABLE public.bapperida_inovasi ADD COLUMN IF NOT EXISTS anggaran_inovasi VARCHAR(100);
ALTER TABLE public.bapperida_inovasi ADD COLUMN IF NOT EXISTS waktu_uji_coba DATE;
ALTER TABLE public.bapperida_inovasi ADD COLUMN IF NOT EXISTS waktu_penerapan DATE;

SELECT 
  (SELECT json_agg(t) FROM (SELECT id, judul, konten, kategori, tanggal, emoji, gambar_data AS gambar_url, is_featured, priority, layout_size, col_span, row_span FROM public.bapperida_berita ORDER BY priority ASC, id DESC) t) AS berita,
  (SELECT json_agg(t) FROM (SELECT id, judul, kategori, tipe, ukuran, tanggal, icon_data AS icon, url FROM public.bapperida_dokumen ORDER BY id DESC) t) AS dokumen,
  (SELECT json_agg(t) FROM (SELECT id, gambar_data AS gambar_url, judul, subjudul FROM public.bapperida_slider ORDER BY id ASC) t) AS slider,
  (SELECT json_agg(t) FROM (SELECT id, icon_data AS icon, title, cat, "desc", status, sc, priority FROM public.bapperida_program ORDER BY priority ASC, id ASC) t) AS program,
  (SELECT json_agg(t) FROM (SELECT id, label, value, icon FROM public.bapperida_metrics ORDER BY priority ASC) t) AS metrics,
  (SELECT json_agg(t) FROM (SELECT * FROM public.bapperida_inovasi WHERE status_approval = 'Approved' ORDER BY skor_iga DESC, id DESC) t) AS inovasi;
